import React, { useState } from "react";
import { Camera, CameraResultType, CameraSource } from "@capacitor/camera";

function App() {
  const [photo, setPhoto] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [recognizedName, setRecognizedName] = useState("");

  const takePhoto = async () => {
    try {
      const image = await Camera.getPhoto({
        quality: 100, // OCR 인식률을 높이기 위해 최대 품질 설정
        allowEditing: true, // 촬영 후 약 이름 부분만 자를 수 있도록 편집 허용
        resultType: CameraResultType.Uri,
        source: CameraSource.Camera,
        saveToGallery: true,
      });
      setPhoto(image.webPath);
      setRecognizedName(""); // 새로운 사진 촬영 시 기존 인식 결과 초기화
    } catch (err) {
      console.error("카메라 오류:", err);
    }
  };

  const deletePhoto = () => {
    setPhoto(null);
    setRecognizedName("");
  };

  const uploadAndRecognize = async () => {
    if (!photo) return;
    setUploading(true);

    // 기능: 서버 API 호출 및 OCR 결과 수신 시뮬레이션
    setTimeout(() => {
      setUploading(false);
      setRecognizedName("타이레놀 80mg"); // 인식 결과 데이터 삽입
      alert("글자 인식이 완료되었습니다. 약 이름을 확인해주세요!");
    }, 2000);
  };

  const useHover = () => {
    const [hover, setHover] = useState(false);
    const onMouseEnter = () => setHover(true);
    const onMouseLeave = () => setHover(false);
    return [hover, { onMouseEnter, onMouseLeave }];
  };

  const [mainBtnHover, mainBtnHoverEvents] = useHover();
  const [uploadBtnHover, uploadBtnHoverEvents] = useHover();

  return (
    <div style={wrapperStyle}>
      <header style={headerStyle}>
        <div style={headerContentStyle}>
          <h1 style={headerTitleStyle}>Pill Scanner OCR</h1>
        </div>
      </header>

      <main style={mainStyle}>
        <div style={photoCardStyle}>
          {photo ? (
            <>
              <img src={photo} alt="Preview" style={imageStyle} />
              <button onClick={deletePhoto} style={closeButtonStyle}>
                ✕
              </button>
            </>
          ) : (
            <div style={placeholderStyle}>
              <div style={placeholderIconStyle}>🔍</div>
              <p style={placeholderTextStyle}>약봉지 스캔 대기 중</p>
              <p style={placeholderSubTextStyle}>
                글자가 잘 보이게 촬영해주세요
              </p>
            </div>
          )}
        </div>

        <div style={infoSectionStyle}>
          {photo && !uploading && !recognizedName && (
            <p style={statusStyle}>사진이 준비되었습니다. 인식을 시작하세요!</p>
          )}

          {uploading && (
            <div style={loadingAreaStyle}>
              <div style={spinnerStyle}></div>
              <p style={{ ...statusStyle, marginTop: 10 }}>
                글자를 분석하고 있습니다...
              </p>
            </div>
          )}

          {recognizedName && (
            <div style={resultContainerStyle}>
              <label style={labelStyle}>인식된 약 이름 (수정 가능)</label>
              <input
                style={inputStyle}
                value={recognizedName}
                onChange={(e) => setRecognizedName(e.target.value)} // 기능: 사용자가 인식 결과를 직접 수정 가능
                placeholder="인식된 이름이 여기에 나타납니다"
              />
            </div>
          )}
        </div>
      </main>

      <footer style={footerStyle}>
        {!photo ? (
          <button
            onClick={takePhoto}
            style={{
              ...mainButtonStyle,
              ...(mainBtnHover ? mainButtonStyleHover : {}),
            }}
            {...mainBtnHoverEvents}
          >
            약봉지 촬영하기
          </button>
        ) : (
          <button
            onClick={uploadAndRecognize}
            style={{
              ...mainButtonStyle,
              backgroundColor: recognizedName ? "#6c757d" : "#28a745",
              ...(uploadBtnHover
                ? { transform: "scale(1.02)", opacity: 0.9 }
                : {}),
            }}
            disabled={uploading}
            {...uploadBtnHoverEvents}
          >
            {uploading
              ? "인식 중..."
              : recognizedName
              ? "다시 인식하기"
              : "약 이름 인식 시작"}
          </button>
        )}
      </footer>
    </div>
  );
}

const wrapperStyle = {
  backgroundColor: "#f8f9fa",
  minHeight: "100vh",
  display: "flex",
  flexDirection: "column",
  fontFamily: "-apple-system, sans-serif",
};

const headerStyle = {
  paddingTop: "calc(env(safe-area-inset-top, 44px) + 10px)",
  paddingBottom: "15px",
  backgroundColor: "#fff",
  display: "flex",
  justifyContent: "center",
  borderBottom: "1px solid #eee",
};

const headerContentStyle = { display: "flex", alignItems: "center" };
const headerTitleStyle = {
  fontSize: "20px",
  margin: 0,
  fontWeight: "800",
  color: "#007bff",
};

const mainStyle = {
  flex: 1,
  padding: "20px",
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
};

const photoCardStyle = {
  width: "100%",
  maxWidth: "360px",
  aspectRatio: "1/1",
  backgroundColor: "#fff",
  borderRadius: "24px",
  boxShadow: "0 10px 30px rgba(0,0,0,0.08)",
  position: "relative",
  overflow: "hidden",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
};

const imageStyle = { width: "100%", height: "100%", objectFit: "cover" };
const placeholderStyle = { textAlign: "center" };
const placeholderIconStyle = { fontSize: "50px", marginBottom: "10px" };
const placeholderTextStyle = {
  fontSize: "18px",
  fontWeight: "bold",
  color: "#333",
  margin: "5px 0",
};
const placeholderSubTextStyle = { fontSize: "14px", color: "#888", margin: 0 };

const closeButtonStyle = {
  position: "absolute",
  top: "15px",
  right: "15px",
  width: "32px",
  height: "32px",
  borderRadius: "50%",
  backgroundColor: "rgba(0,0,0,0.5)",
  color: "#fff",
  border: "none",
  fontSize: "14px",
  zIndex: 10,
};

const infoSectionStyle = {
  width: "100%",
  maxWidth: "360px",
  marginTop: "30px",
  textAlign: "center",
};
const statusStyle = { fontSize: "15px", color: "#555", margin: 0 };

const resultContainerStyle = { textAlign: "left" };
const labelStyle = {
  fontSize: "13px",
  color: "#007bff",
  fontWeight: "bold",
  marginLeft: "5px",
};
const inputStyle = {
  width: "100%",
  padding: "15px",
  marginTop: "8px",
  borderRadius: "12px",
  border: "2px solid #007bff",
  fontSize: "16px",
  fontWeight: "600",
  boxSizing: "border-box",
  outline: "none",
  backgroundColor: "#fff",
};

const loadingAreaStyle = {
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
};
const spinnerStyle = {
  width: "30px",
  height: "30px",
  border: "3px solid #f3f3f3",
  borderTop: "3px solid #007bff",
  borderRadius: "50%",
  animation: "spin 1s linear infinite",
};

const footerStyle = {
  padding: "20px 20px calc(env(safe-area-inset-bottom) + 20px)",
  backgroundColor: "#fff",
  borderTop: "1px solid #eee",
};

const mainButtonStyle = {
  width: "100%",
  padding: "20px",
  borderRadius: "16px",
  border: "none",
  backgroundColor: "#007bff",
  color: "#fff",
  fontSize: "18px",
  fontWeight: "bold",
  transition: "all 0.2s",
  boxShadow: "0 5px 15px rgba(0,123,255,0.3)",
};

const mainButtonStyleHover = {
  transform: "translateY(-2px)",
  boxShadow: "0 8px 20px rgba(0,123,255,0.4)",
};

export default App;
